 81→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 82→  switch (entry.type) {
 83→    case 'label':
 84→      return (
 85→        <DetailMetadata.Label
 86→          key={index}
 87→          title={entry.title}
 88→          text={entry.text}
 89→        />
 90→      );
 91→    case 'link':
 92→      return (
 93→        <DetailMetadata.Link
 94→          key={index}
 95→          title={entry.title}
 96→          text={entry.text}
 97→          target={entry.target}
 98→        />
 99→      );
100→    case 'tag-list':
101→      return (
102→        <DetailMetadata.TagList key={index} title={entry.title}>
103→          {entry.tags.map(tag => (
104→            <DetailMetadata.Tag
105→              key={tag.text}
106→              text={tag.text}
107→              color={tag.color}
108→            />
109→          ))}
110→        </DetailMetadata.TagList>
111→      );
112→    case 'separator':
113→      return <DetailMetadata.Separator key={index} />;
114→  }
115→}
