784→      case 'snippets':
785→        return <SnippetManagerView />;
786→      case 'emoji':
787→        return <EmojiPickerView />;
788→      case 'file-search':
789→        return <FileSearchView />;
790→      case 'settings':
791→        return <SettingsView />;
792→      case 'grid':
793→        return (
794→          <ColorPickerView
795→            key={colorFilterValue}
796→            colors={filteredColors}
797→            onActiveIndexChange={handleActiveIndexChange}
798→            onAction={handleGridAction}
799→          />
800→        );
801→      case 'detail':
802→        return <DetailView item={entry.data.item} />;
803→    }
804→  }
805→
806→  const isFullView =
807→    viewType === 'clipboard' ||
808→    viewType === 'snippets' ||
809→    viewType === 'emoji' ||
810→    viewType === 'file-search' ||
811→    viewType === 'settings';
812→
813→  return (
814→    <NavigationContextProvider value={nav}>
815→      <CommandPalette isLoading>
816→        {!isFullView && (
817→          <SearchBar
818→            value={query}
819→            onChange={handleQueryChange}
820→            activeDescendantId={activeDescendantId}
821→            breadcrumbs={
822→              nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined
823→            }
824→            dropdown={
825→              viewType === 'root' ? (
826→                <SearchDropdown
827→                  sections={searchFilterSections}
828→                  value={filterValue}
829→                  onChange={handleFilterChange}
830→                />
831→              ) : viewType === 'grid' ? (
832→                <SearchDropdown
833→                  sections={colorFilterSections}
834→                  value={colorFilterValue}
835→                  onChange={handleColorFilterChange}
836→                />
837→              ) : undefined
838→            }
839→          />
840→        )}
841→        {isFullView && nav.currentEntry ? (
842→          <div
843→            key={nav.navKey}
844→            className={`command-palette__nav-view${navDirectionClass}`}
845→          >
846→            {renderCurrentView()}
847→          </div>
848→        ) : nav.currentEntry ? (
849→          <div
850→            key={nav.navKey}
851→            className={`command-palette__nav-view${navDirectionClass}`}
852→          >
853→            <div className="command-palette__body">
854→              <div className="command-palette__list-container">
855→                {renderCurrentView()}
856→              </div>
857→            </div>
858→          </div>
859→        ) : (
860→          <div
861→            className={`command-palette__body${detail ? ' command-palette__body--has-detail' : ''}`}
862→          >
863→            <div className="command-palette__list-container">
864→              {allItems.length === 0 ? (
865→                <EmptyState
866→                  icon={<SearchIcon />}
867→                  title="No Results"
868→                  description="Try a different search term"
869→                />
870→              ) : (
871→                <List
872→                  itemCount={allItems.length}
873→                  onActiveIndexChange={handleActiveIndexChange}
874→                  onAction={handleDrillIn}
875→                >
876→                  {(() => {
