type SettingsTab = 'general' | 'extensions' | 'advanced';

const SETTINGS_TABS: SettingsTab[] = ['general', 'extensions', 'advanced'];

function isSettingsTab(value: string): value is SettingsTab {
  return SETTINGS_TABS.includes(value as SettingsTab);
}

interface GeneralSettings {
  appearance: string;
  windowWidth: string;
  showRecentApps: boolean;
  showDock: boolean;
  fontSize: string;
}

const TAB_SECTIONS: SearchDropdownSection[] = [
  {
    options: [
      {
        label: 'General',
        value: 'general',
      },
      {
        label: 'Extensions',
        value: 'extensions',
      },
      {
        label: 'Advanced',
        value: 'advanced',
      },
    ],
  },
];

const APPEARANCE_OPTIONS = [
  {
    label: 'Dark',
    value: 'dark',
  },
  {
    label: 'Light',
    value: 'light',
  },
  {
    label: 'System',
    value: 'system',
  },
];

const WINDOW_WIDTH_OPTIONS = [
  {
    label: 'Small (680px)',
    value: 'small',
  },
