@use '../../styles/tokens' as *;

.settings-view {
  display: flex;
  flex-direction: column;
  flex: 1;
  overflow-y: auto;
}

.settings-section {
  padding: $space-3 $space-4 $space-1;

  &__title {
    font-size: $font-xs;
    font-weight: $font-weight-medium;
    color: $text-600;
    letter-spacing: 0.1px;
    margin-bottom: $space-2;
  }
}

.settings-extension {
  display: flex;
  align-items: center;
  gap: $space-3;
  padding: $space-2 $space-3;
  border-radius: $radius-list-item;
  cursor: pointer;
  transition: background-color $transition-fast ease;

  &:hover {
    background: $color-surface-hover;
  }

  &__icon {
    flex-shrink: 0;
    width: 28px;
    height: 28px;
    display: flex;
    align-items: center;
    justify-content: center;

    svg {
      width: 28px;
      height: 28px;
    }
  }

  &__info {
    flex: 1;
    min-width: 0;
  }

  &__name {
    font-size: $font-base;
    color: $color-text-primary;
    font-weight: $font-weight-medium;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  &__meta {
    font-size: $font-xs;
    color: $text-400;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  &__toggle {
    flex-shrink: 0;
  }
}

$toggle-width: 36px;
$toggle-height: 20px;
$toggle-knob-size: 16px;
$toggle-padding: 2px;

.settings-toggle {
  position: relative;
  display: inline-flex;
  align-items: center;
  cursor: pointer;
}

.settings-toggle__input {
  position: absolute;
  opacity: 0;
  width: 0;
  height: 0;
  pointer-events: none;

  &:focus-visible + .settings-toggle__track {
    outline: 2px solid $color-accent;
    outline-offset: 2px;
  }
}

.settings-toggle__track {
  width: $toggle-width;
  height: $toggle-height;
  border-radius: $radius-pill;
  background: $text-100;
  transition: background-color $transition-normal ease;
  pointer-events: none;

  .settings-toggle__input:checked + & {
    background: $color-accent;
  }
}

.settings-toggle__knob {
  position: absolute;
  top: $toggle-padding;
  left: $toggle-padding;
  width: $toggle-knob-size;
  height: $toggle-knob-size;
  border-radius: 50%;
  background: white;
  transition: transform $transition-normal ease;
  pointer-events: none;

  .settings-toggle__input:checked ~ & {
    transform: translateX(
      #{$toggle-width - $toggle-knob-size - $toggle-padding * 2}
    );
  }
}

.settings-hotkey {
  display: flex;
  align-items: center;
  gap: $space-1;
  padding: $space-2 0;

  &__label {
    font-size: $font-sm;
    color: $text-600;
    font-weight: $font-weight-semibold;
    flex: 1;
  }
}

.settings-action-row {
  display: flex;
  align-items: center;
  gap: $space-3;
  padding: $space-2 $space-3;
