            </div>
          )}
          {communityExts.length > 0 && (
            <div className="settings-section">
              <div className="settings-section__title">Community</div>
              {communityExts.map(ext => (
                <ExtensionRow
                  key={ext.id}
                  ext={ext}
                  onToggle={onToggle}
                  showAuthor
                />
              ))}
            </div>
          )}
        </>
      )}
    </div>
  );
}

